     1→const express = require('express');
     2→const Anthropic = require('@anthropic-ai/sdk');
     3→const rateLimit = require('express-rate-limit');
     4→const { verifyToken } = require('../middleware/firebaseAuth');
     5→
     6→const router = express.Router();
     7→
     8→const client = new Anthropic({
     9→  apiKey: process.env.ANTHROPIC_API_KEY,
    10→});
    11→
    12→// Rate limiter: 60 requests per 15 minutes per IP
    13→const aiLimiter = rateLimit({
    14→  windowMs: 15 * 60 * 1000,
    15→  max: 60,
    16→  message: { error: 'Too many requests, please try again later.' },
    17→  standardHeaders: true,
    18→  legacyHeaders: false,
    19→});
    20→
    21→// Category/tool definitions (mirrors frontend data/categories.js — system prompts and builders)
    22→// We re-import these here so backend is the source of truth for prompts
    23→const CATEGORY_PROMPTS = require('./categoryPrompts');
    24→
    25→// POST /api/ai/generate  — streaming SSE response
    26→router.post('/generate', aiLimiter, verifyToken, async (req, res) => {
    27→  const { categoryId, toolId, inputs } = req.body;
    28→
    29→  if (!categoryId || !toolId || !inputs) {
    30→    return res.status(400).json({ error: 'Missing required fields: categoryId, toolId, inputs' });
    31→  }
    32→
    33→  // Look up the tool config
    34→  const tool = CATEGORY_PROMPTS[categoryId]?.[toolId];
    35→  if (!tool) {
    36→    return res.status(404).json({ error: `Tool "${toolId}" not found in category "${categoryId}"` });
    37→  }
    38→
    39→  // Check subscription for premium categories (read from Firestore for accuracy)
    40→  const freeCategoryIds = ['marketing', 'content'];
    41→  let userSubscription = req.user?.subscription || 'free'; // fallback (used in dev mode)
    42→  try {
    43→    const adminSdk = require('firebase-admin');
    44→    if (adminSdk.apps.length > 0) {
    45→      const fsDb = adminSdk.firestore();
    46→      const userDoc = await fsDb.collection('users').doc(req.user.uid).get();
    47→      if (userDoc.exists) {
    48→        userSubscription = userDoc.data().subscription || 'free';
    49→      }
    50→    }
    51→  } catch (_) { /* use fallback */ }
    52→
    53→  if (!freeCategoryIds.includes(categoryId) && userSubscription === 'free') {
    54→    return res.status(403).json({
    55→      error: 'This category requires a Pro or Business subscription.',
    56→      upgradeRequired: true,
    57→    });
    58→  }
    59→
    60→  // Language instruction based on user preference
    61→  const LANGUAGE_NAMES = { en: 'English', es: 'Spanish', fr: 'French', de: 'German', it: 'Italian' };
    62→  const lang = inputs._language && LANGUAGE_NAMES[inputs._language] ? inputs._language : 'en';
    63→  const languageInstruction = lang !== 'en'
    64→    ? `\n\nIMPORTANT: You MUST respond entirely in ${LANGUAGE_NAMES[lang]}. All section titles, content, analysis, tables and text must be written in ${LANGUAGE_NAMES[lang]}.`
    65→    : '';
    66→
    67→  const systemPrompt = tool.systemPrompt + languageInstruction;
    68→  const userMessage = tool.buildUserMessage(inputs);
    69→
    70→  // Set SSE headers
    71→  res.setHeader('Content-Type', 'text/event-stream');
    72→  res.setHeader('Cache-Control', 'no-cache');
    73→  res.setHeader('Connection', 'keep-alive');
    74→  res.setHeader('X-Accel-Buffering', 'no');
    75→  res.flushHeaders();
    76→
    77→  try {
    78→    const stream = client.messages.stream({
    79→      model: 'claude-opus-4-5',
    80→      max_tokens: 4096,
    81→      system: systemPrompt,
    82→      messages: [{ role: 'user', content: userMessage }],
    83→    });
    84→
    85→    stream.on('text', (text) => {
    86→      res.write(`data: ${JSON.stringify({ text })}\n\n`);
    87→    });
    88→
    89→    stream.on('error', (err) => {
    90→      console.error('[AI Stream Error]', err.message);
    91→      res.write(`data: ${JSON.stringify({ error: 'AI generation error' })}\n\n`);
    92→      res.end();
    93→    });
    94→
    95→    stream.on('end', () => {
    96→      res.write('data: [DONE]\n\n');
    97→      res.end();
    98→    });
    99→
   100→    // Handle client disconnect
   101→    req.on('close', () => {
   102→      stream.abort();
   103→    });
   104→  } catch (err) {
   105→    console.error('[AI Route Error]', err.message);
   106→    if (!res.headersSent) {
   107→      return res.status(500).json({ error: 'Failed to generate AI response' });
   108→    }
   109→    res.write(`data: ${JSON.stringify({ error: err.message })}\n\n`);
   110→    res.end();
   111→  }
   112→});
   113→
   114→module.exports = router;
   115→

