```javascript
router.post('/generate', aiLimiter, verifyToken, async (req, res) => {
  const { categoryId, toolId, inputs } = req.body;

  // 1. REQUIRED FIELDS VALIDATION
  if (!categoryId || !toolId || !inputs) {
    return res.status(400).json({ 
      error: 'Missing required fields: categoryId, toolId, inputs' 
    });
  }

  // 2. TOOL LOOKUP & VALIDATION
  const tool = CATEGORY_PROMPTS[categoryId]?.[toolId];
  if (!tool) {
    return res.status(404).json({ 
      error: `Tool "${toolId}" not found in category "${categoryId}"` 
    });
  }

  // 3. SUBSCRIPTION VALIDATION (Free vs Premium)
  const freeCategoryIds = ['marketing', 'content'];
  let userSubscription = req.user?.subscription || 'free';

  try {
    const adminSdk = require('firebase-admin');
    if (adminSdk.apps.length > 0) {
      const fsDb = adminSdk.firestore();
      const userDoc = await fsDb.collection('users').doc(req.user.uid).get();
      if (userDoc.exists) {
        userSubscription = userDoc.data().subscription || 'free';
      }
    }
  } catch (_) { /* use fallback */ }

  if (!freeCategoryIds.includes(categoryId) && userSubscription === 'free') {
    return res.status(403).json({
      error: 'This category requires a Pro or Business subscription.',
      upgradeRequired: true,
    });
  }
```

#### Rate Limiting:
```javascript
const aiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 60,                    // 60 requests max
  message: { error: 'Too many requests, please try again later.' },
});
```

#### Authentication Middleware:
- Requires Firebase ID token in `Authorization: Bearer <token>` header
- Validates via `verifyToken` middleware
- Falls back to dev mode if Firebase not configured

#### Response Format:
- Server-Sent Events (SSE) streaming
- Real-time text chunks via `data: {...}` format
- Language support (EN/ES/FR/DE/IT)

```javascript
const LANGUAGE_NAMES = { 
