### 5. Authentication Middleware: `/Users/gabiorma/gormaran-ai-growth-hub/server/middleware/firebaseAuth.js`

```javascript
async function verifyToken(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    // Dev mode: allow pass-through if Firebase not configured
    if (!process.env.FIREBASE_PROJECT_ID || 
        process.env.FIREBASE_PROJECT_ID === 'your_project_id') {
      req.user = { 
        uid: 'dev-user', 
        email: 'dev@localhost', 
        subscription: 'pro' 
      };
      return next();
    }
    return res.status(401).json({ error: 'Unauthorized — missing token' });
  }

  const token = authHeader.split('Bearer ')[1];
  try {
    const decoded = await admin.auth().verifyIdToken(token);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Unauthorized — invalid token' });
  }
}
```

